201	    // Structural spot-checks on the frame itself.
202	    let out = render_theory(&thy, &sig);
203	    assert!(out.starts_with("theory Demo\n\nbegin\n\n"), "header rhythm");
204	    assert!(out.ends_with("by sorry\n\n\n\nend"), "3-blank pre-end tail");
205	    // Signature is first (immediately after `begin`), items keep source order.
206	    let sig_at = out.find("// Function signature").unwrap();
207	    let heur_at = out.find("heuristic: p").unwrap();
208	    let rule_at = out.find("rule (modulo E) R").unwrap();
209	    let lem_at = out.find("lemma Bar").unwrap();
210	    assert!(sig_at < heur_at && heur_at < rule_at && rule_at < lem_at, "item order");
211	}
