730	// ── block parsers ───────────────────────────────────────────────────────────
731	
732	fn parse_rule_block(block: &str) -> (Rule, Option<AcVariants>) {
733	    let mut p = P::new(block);
734	    let mut r = p.rule_core();
735	    if p.starts("//") {
736	        r.loop_breakers = p.breaker_line();
737	    }
738	    p.expect("/*");
739	    if p.eat("has exactly the trivial AC variant") {
740	        p.expect("*/");
741	        return (r, None);
742	    }
743	    let mut ac = p.rule_core();
744	    let mut substitutions: Vec<Vec<(Term, Term)>> = Vec::new();
745	    if p.eat("variants (modulo AC)") {
746	        loop {
747	            if p.starts("*/") || p.starts("//") {
748	                break;
749	            }
750	            p.ws();
751	            if p.rest().chars().next().is_some_and(|c| c.is_ascii_digit()) {
752	                let n: usize = p.digits().parse().unwrap();
753	                p.expect(".");
754	                assert_eq!(n, substitutions.len() + 1, "group numbering");
755	                substitutions.push(Vec::new());
756	                continue;
757	            }
758	            let lhs = p.term();
759	            p.expect("=");
760	            let rhs = p.term();
761	            substitutions
762	                .last_mut()
763	                .expect("substitution before group index")
764	                .push((lhs, rhs));
765	        }
766	    }
767	    if p.starts("//") {
768	        ac.loop_breakers = p.breaker_line();
769	    }
770	    p.expect("*/");
771	    (r, Some(AcVariants { ac_rule: ac, substitutions }))
772	}
773	
774	fn parse_restriction_block(block: &str) -> Restriction {
775	    let stmt_end = block.find("\n\n").expect("restriction comment separator");
776	    let stmt = &block[..stmt_end];
777	    let mut p = P::new(stmt);
778	    p.expect("restriction");
779	    p.ws();
780	    let name: String = p.rest().chars().take_while(|c| *c != ':').collect();
781	    p.pos += name.len();
782	    p.expect(":");
783	    p.expect("\"");
784	    let formula = p.formula();
785	    p.expect("\"");
786	    let _ = p.eat("// safety formula");
787	    let comment = &block[stmt_end..];
788	    let ex_hdr = "expanded formula:";
789	    let ex_idx = comment.find(ex_hdr).expect("expanded formula header");
790	    let mut pe = P::new(&comment[ex_idx + ex_hdr.len()..]);
791	    pe.expect("\"");
792	    let expanded = pe.formula();
793	    pe.expect("\"");
794	    Restriction { name, formula, expanded }
795	}
796	
797	fn parse_lemma_block(block: &str) -> (Lemma, Option<Guarded>) {
798	    let lines: Vec<&str> = block.lines().collect();
799	    let open = lines.iter().position(|l| *l == "/*").expect("guarded comment opener");
800	    let close = open + 1 + lines[open + 1..].iter().position(|l| *l == "*/").expect("guarded closer");
801	    let head = lines[..open].join("\n");
802	    let mut p = P::new(&head);
803	    p.expect("lemma");
804	    p.ws();
805	    let name: String = p
806	        .rest()
807	        .chars()
808	        .take_while(|c| !c.is_whitespace() && *c != '[' && *c != ':')
809	        .collect();
810	    p.pos += name.len();
811	    p.ws();
812	    let attributes = if p.eat("[") {
813	        let a = p.lemma_attrs();
814	        p.expect("]");
815	        a
816	    } else {
817	        Vec::new()
818	    };
819	    p.expect(":");
820	    let trace_quantifier = if p.eat("all-traces") {
821	        TraceQuantifier::AllTraces
822	    } else {
823	        p.expect("exists-trace");
824	        TraceQuantifier::ExistsTrace
825	    };
826	    p.expect("\"");
827	    let formula = p.formula();
828	    p.expect("\"");
829	    p.ws();
830	    assert!(p.rest().is_empty(), "unparsed lemma head: {:?}", p.rest());
831	    let header = lines[open + 1];
832	    let content = lines[open + 2..close].join("\n");
833	    let guarded = if header == "conversion to guarded formula failed:" {
834	        let stripped: Vec<String> = lines[open + 2..close]
835	            .iter()
836	            .map(|l| l.strip_prefix("  ").unwrap_or(l).to_string())
837	            .collect();
838	        Guarded::Failed(stripped.join("\n"))
839	    } else {
840	        Guarded::Formula(content)
841	    };
842	    let tail = lines[close + 1..].join("\n");
843	    let proof = if tail == "by sorry" { None } else { Some(tail) };
844	    (Lemma { name, attributes, trace_quantifier, formula, proof }, Some(guarded))
