939	fn parse_function_items(s: &str) -> Vec<FunctionDecl> {
940	    let mut p = P::new(s);
941	    let mut out = Vec::new();
942	    loop {
943	        p.ws();
944	        if p.rest().is_empty() {
945	            break;
946	        }
947	        let name: String = p.rest().chars().take_while(|c| *c != '/').collect();
948	        p.pos += name.len();
949	        p.expect("/");
950	        let arity: usize = p.digits().parse().unwrap();
951	        let (mut private, mut destructor) = (false, false);
952	        if p.rest().starts_with('[') {
953	            let end = p.rest().find(']').expect("unterminated attr");
954	            let attrs = &p.rest()[1..end];
955	            private = attrs.contains("private");
956	            destructor = attrs.contains("destructor");
957	            p.pos += end + 1;
958	        }
959	        out.push(FunctionDecl { name, arity, private, destructor });
960	        if !p.eat(",") {
961	            break;
962	        }
963	    }
964	    out
965	}
