967	fn parse_equations(s: &str) -> Vec<Equation> {
968	    let mut p = P::new(s);
969	    let mut out = Vec::new();
970	    loop {
971	        p.ws();
972	        if p.rest().is_empty() {
973	            break;
974	        }
975	        let lhs = p.term();
976	        p.expect("=");
977	        let rhs = p.term();
978	        out.push(Equation { lhs, rhs });
979	        if !p.eat(",") {
980	            break;
981	        }
982	    }
983	    out
984	}
