992	/// Split one whole extracted echo into `(name, Signature, Vec<TheoryItem>)`.
993	fn parse_theory(capture: &str) -> (String, Signature, Vec<TheoryItem>) {
994	    let body = capture.strip_suffix('\n').unwrap_or(capture);
995	    let lines: Vec<&str> = body.lines().collect();
996	    assert!(lines[0].starts_with("theory "), "no theory header");
997	    let name = lines[0]["theory ".len()..].trim().to_string();
998	    assert_eq!(lines[1], "", "blank after theory name");
999	    assert_eq!(lines[2], "begin", "begin line");
1000	    assert_eq!(lines[3], "", "blank after begin");
1001	    let n = lines.len();
1002	    // Trailing frame: `<3 blank lines> end`.
1003	    assert_eq!(lines[n - 1], "end", "end line");
1004	    assert!(
1005	        is_blank(lines[n - 2]) && is_blank(lines[n - 3]) && is_blank(lines[n - 4]),
1006	        "expected 3 blank lines before end"
1007	    );
1008	    let inner = &lines[4..n - 4];
1009	
1010	    // Signature: `// header`, blank, then the declaration run up to a blank.
1011	    assert!(inner[0].starts_with("// Function signature"), "signature header");
1012	    assert_eq!(inner[1], "", "blank after signature header");
1013	    let mut k = 2;
1014	    while k < inner.len() && !is_blank(inner[k]) {
1015	        k += 1;
1016	    }
1017	    let sig = parse_signature(&inner[2..k].join("\n"));
1018	
1019	    let mut items: Vec<TheoryItem> = Vec::new();
1020	    let mut i = k;
1021	    while i < inner.len() {
1022	        if is_blank(inner[i]) {
1023	            i += 1;
1024	            continue;
1025	        }
1026	        let line = inner[i];
1027	        if line.starts_with("macros:") {
1028	            let (block, next) = take_until_blank(inner, i);
1029	            items.push(TheoryItem::Macros(parse_macros_block(&block)));
1030	            i = next;
1031	        } else if line.starts_with("predicate:") {
1032	            // Group the whole contiguous run of predicate blocks into one item.
1033	            let mut preds = Vec::new();
1034	            while i < inner.len() && inner[i].starts_with("predicate:") {
1035	                let (block, next) = take_until_blank(inner, i);
1036	                preds.push(parse_predicate_block(&block));
1037	                i = next;
1038	                while i < inner.len() && is_blank(inner[i]) {
1039	                    i += 1;
1040	                }
1041	            }
1042	            items.push(TheoryItem::Predicates(preds));
1043	        } else if let Some(v) = line.strip_prefix("heuristic:") {
1044	            items.push(TheoryItem::Heuristic(v.trim().to_string()));
1045	            i += 1;
1046	        } else if line.starts_with("tactic:")
1047	            || line.starts_with("section{*")
1048	            || line.starts_with("subsection{*")
1049	            || line.starts_with("text{*")
1050	            || line.starts_with("options")
1051	        {
1052	            // Opaque top-level block: everything up to the next blank line.
1053	            let (block, next) = take_until_blank(inner, i);
1054	            items.push(TheoryItem::Verbatim(block));
1055	            i = next;
1056	        } else if line.starts_with("rule ") {
1057	            let (block, next) = take_rule_block(inner, i);
1058	            let (r, v) = parse_rule_block(&block);
1059	            items.push(TheoryItem::Rule(r, v));
1060	            i = next;
1061	        } else if line.starts_with("restriction ") {
1062	            let (block, next) = take_until_line(inner, i, "  */");
1063	            items.push(TheoryItem::Restriction(parse_restriction_block(&block)));
1064	            i = next;
1065	        } else if line.starts_with("lemma ") {
1066	            let (block, next) = take_lemma_block(inner, i);
1067	            let (l, g) = parse_lemma_block(&block);
1068	            items.push(TheoryItem::Lemma(l, g));
1069	            i = next;
1070	        } else if line.starts_with("/*") {
1071	            // A top-level formal comment carried verbatim: the theory-level
1072	            // `/* looping facts with injective instances: … */` note (single
1073	            // line) or a multi-line `/* … */` user comment (through its col-0
1074	            // `*/`).
1075	            let (block, next) = if line.trim_end().ends_with("*/") {
1076	                (line.to_string(), i + 1)
1077	            } else {
1078	                take_until_line(inner, i, "*/")
1079	            };
1080	            items.push(TheoryItem::Verbatim(block));
1081	            i = next;
1082	        } else {
1083	            panic!("unrecognised top-level block at line {i}: {line:?}");
1084	        }
1085	    }
1086	    (name, sig, items)
1087	}
