1090	/// joined block and the index just past it.
1091	fn take_until_blank(inner: &[&str], start: usize) -> (String, usize) {
1092	    let mut j = start;
1093	    while j < inner.len() && !is_blank(inner[j]) {
1094	        j += 1;
1095	    }
1096	    (inner[start..j].join("\n"), j)
1097	}
