1099	/// Lines `[start..=<line matching `marker`>]` inclusive.
1100	fn take_until_line(inner: &[&str], start: usize, marker: &str) -> (String, usize) {
1101	    let mut j = start;
1102	    while inner[j] != marker {
1103	        j += 1;
1104	    }
1105	    (inner[start..=j].join("\n"), j + 1)
1106	}
