1108	/// A rule block: header+body, blank, optional loop-breaker line(s), then the
1109	/// variants comment (one-liner or a `/* … */` span).
1110	fn take_rule_block(inner: &[&str], start: usize) -> (String, usize) {
1111	    let mut i = start;
1112	    while i < inner.len() && !is_blank(inner[i]) {
1113	        i += 1;
1114	    }
1115	    let mut j = i + 1;
1116	    while j < inner.len() && inner[j].trim_start().starts_with("// loop breaker") {
1117	        j += 1;
1118	    }
1119	    let end = if inner[j].trim() == "/* has exactly the trivial AC variant */" {
1120	        j
1121	    } else {
1122	        assert_eq!(inner[j].trim(), "/*", "unexpected rule comment opener");
1123	        let mut kk = j + 1;
1124	        while inner[kk].trim() != "*/" {
1125	            kk += 1;
1126	        }
1127	        kk
1128	    };
1129	    (inner[start..=end].join("\n"), end + 1)
1130	}
