1132	/// A lemma block: statement, guarded comment (through its col-0 `*/`), then the
1133	/// tail (`by …` one line, or an embedded proof through `qed`).
1134	fn take_lemma_block(inner: &[&str], start: usize) -> (String, usize) {
1135	    let mut i = start;
1136	    while inner[i] != "*/" {
1137	        i += 1;
1138	    }
1139	    i += 1;
1140	    if inner[i].starts_with("by ") {
1141	        // one-line tail
1142	    } else {
1143	        while inner[i] != "qed" {
1144	            i += 1;
1145	        }
1146	    }
1147	    (inner[start..=i].join("\n"), i + 1)
1148	}
