    Action(Fact, Term),
    /// `last(tp)` — no interior spaces (probe:q_at1).
    Last(Term),
    /// Predicate fact atom. UNOBSERVABLE: predicates are expanded upstream
    /// of the echo (probe:q_pred1) — rendered as a bare fact, flagged.
    Pred(Fact),
}

/// `restriction name: "formula"` plus the conditional `// safety formula`
/// line and the `/* expanded formula: … */` comment (probe:q_w1). The
/// `axiom` keyword echoes as a restriction too (probe:q_ax1).
///
/// `formula` is the STATEMENT as written (macros unexpanded); `expanded` is
/// the macro/predicate-expanded formula shown in the `expanded formula:`
/// comment. They differ ONLY when the restriction uses a macro
/// (target:MacroInLemmasAndRestrictions — statement `A( m(m3(x)) )`, expanded
/// `A( x )`); predicate expansion happens upstream of BOTH, so predicate-only
/// restrictions render the two identically (probe:q_pred1). `expanded` is a
/// caller-supplied opaque input (the ported macro/predicate expansion), NOT
/// derived here.
#[derive(Debug, Clone, PartialEq)]
pub struct Restriction {
    pub name: String,
    pub formula: Formula,
    pub expanded: Formula,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum TraceQuantifier {
    AllTraces,
    ExistsTrace,
}

/// Lemma attributes as observed (probes q_la1, q_la2, q_la3, target:5G_AKA).
/// Rendered in SOURCE order, duplicates kept — no canonicalization
/// (probe:q_la1). Attributes without a corpus/probe witness (left/right,
/// output=…, diff-mode spellings) are NOT modeled — see the UNOBSERVABLE
/// register in BEHAVIOR.md.
#[derive(Debug, Clone, PartialEq)]
pub enum LemmaAttr {
    /// `sources`.
    Sources,
    /// `reuse`.
    Reuse,
    /// `use_induction`.
    UseInduction,
    /// `hide_lemma=<name>`.
    HideLemma(String),
    /// `heuristic=<value>` — the value string is carried verbatim, braces
    /// included (`S`, `{mytac}` — probes q_la2/q_la3).
    Heuristic(String),
}

#[derive(Debug, Clone, PartialEq)]
pub struct Lemma {
    pub name: String,
    pub attributes: Vec<LemmaAttr>,
    pub trace_quantifier: TraceQuantifier,
    pub formula: Formula,
    /// Embedded proof script, re-rendered by the PORTED proof printer and
    /// handed here verbatim (column-0 multi-line text). `None` renders the
    /// no-prove placeholder `by sorry` (probe:q_w1, target:Yubikey).
    pub proof: Option<String>,
}

/// Pre-computed guarded-formula comment body (from the ported guarded
/// transform), rendered inside `/* … */` after the lemma statement. The
/// header line is chosen by the renderer from the lemma's trace quantifier;
/// the CONTENT is opaque input (probe:q_w1, probe:q_r1).
#[derive(Debug, Clone, PartialEq)]
pub enum Guarded {
    /// Successful conversion: the quoted multi-line guarded-formula block
    /// (quotes included), emitted verbatim at column 0.
    Formula(String),
    /// Failed conversion: the raw error text (column-0 lines, as the
    /// transform reports it); the comment frame indents every line by 2
    /// under a `conversion to guarded formula failed:` header (probe:q_r1).
    Failed(String),
}

// ── R4: macros / predicates ─────────────────────────────────────────────────

#[derive(Debug, Clone, PartialEq)]
pub struct Macro {
    pub name: String,
    pub params: Vec<Term>,
    pub body: Term,
}

#[derive(Debug, Clone, PartialEq)]
pub struct Predicate {
    pub name: String,
    pub params: Vec<VarSpec>,
    pub body: Formula,
}

// ── top-level theory ────────────────────────────────────────────────────────

#[derive(Debug, Clone, PartialEq, Default)]
pub struct Theory {
    pub name: String,
    pub items: Vec<TheoryItem>,
}

/// One top-level theory item, in the order it appears in the echo (source
/// order; the signature is NOT an item — it is rendered first from the
/// separate `Signature`). The frame (`theory::render`) stacks these with a
/// blank line between successive items. Rules carry their pre-computed
/// `AcVariants` and lemmas their pre-computed `Guarded` (solver inputs) so the
/// frame can dispatch to the R2/R3 entry points with the right arguments.
#[derive(Debug, Clone, PartialEq)]
pub enum TheoryItem {
    /// The `macros:` block (rendered as one item).
    Macros(Vec<Macro>),
    /// A contiguous run of `predicate:` declarations (rendered as one item,
    /// blank-line separated internally).
    Predicates(Vec<Predicate>),
    /// One `rule (modulo E) …` block plus its AC-variants comment.
    Rule(Rule, Option<AcVariants>),
    /// One `restriction …` block (also legacy `axiom`).
    Restriction(Restriction),
    /// One `lemma …` block plus its guarded-formula comment.
    Lemma(Lemma, Option<Guarded>),
    /// A theory-level `heuristic: <value>` line.
    Heuristic(String),
    /// An opaque top-level block carried through the frame VERBATIM (the
    /// whole contiguous `tactic:` region, `section{* … *}` / `text{* … *}`
    /// formal comments, `options`, user `/* … */` comments, …). Like the
    /// guarded and proof text, its interior layout is outside this crate's
    /// erasure surface — it is a pre-rendered input, re-emitted unchanged.
    Verbatim(String),
